/**
 * Solution using Persistent Segment Trees (PST) to solve the dynamic programming problem
 * in O(N log V) time, where V is the maximum value in nums (10^5).
 */

function solve(nums, k) {
    const N = nums.length;
    if (N === 0) return 0;

    // Maximum value constraint is 10^5. We use 1-based indexing for values.
    const V_MAX = 100000; 

    // --- Persistent Segment Tree Node Structure ---
    class Node {
        constructor(maxVal = 0, left = null, right = null) {
            this.maxVal = maxVal;
            this.left = left;
            this.right = right;
        }
    }

    // --- PST Operations ---

    // Function to update the segment tree (creates a new path of nodes)
    // Returns the root of the new tree version.
    function updatePST(prevNode, start, end, index, value) {
        // Create a new node by copying the previous one
        const newNode = new Node(prevNode ? prevNode.maxVal : 0, prevNode ? prevNode.left : null, prevNode ? prevNode.right : null);

        newNode.maxVal = Math.max(newNode.maxVal, value);

        if (start === end) {
            // Reached the leaf node corresponding to 'index' (value)
            return newNode;
        }

        const mid = Math.floor((start + end) / 2);

        if (index <= mid) {
            // Go left: create new left child based on old left child
            const prevLeft = prevNode && prevNode.left ? prevNode.left : null;
            newNode.left = updatePST(prevLeft, start, mid, index, value);
        } else {
            // Go right: create new right child based on old right child
            const prevRight = prevNode && prevNode.right ? prevNode.right : null;
            newNode.right = updatePST(prevRight, mid + 1, end, index, value);
        }

        // Recalculate maxVal for the new node
        let leftMax = newNode.left ? newNode.left.maxVal : 0;
        let rightMax = newNode.right ? newNode.right.maxVal : 0;
        newNode.maxVal = Math.max(leftMax, rightMax);

        return newNode;
    }

    // Function to query the segment tree for maximum value in range [L, R]
    function queryPST(node, start, end, L, R) {
        if (!node || L > end || R < start || L > R) {
            return 0;
        }
        if (L <= start && end <= R) {
            return node.maxVal;
        }

        const mid = Math.floor((start + end) / 2);

        const leftMax = queryPST(node.left, start, mid, L, R);
        const rightMax = queryPST(node.right, mid + 1, end, L, R);

        return Math.max(leftMax, rightMax);
    }

    // --- DP Initialization ---

    // DP_UP[i]: Max score ending at i, where nums[i] > nums[j] (increasing step)
    // DP_DOWN[i]: Max score ending at i, where nums[i] < nums[j] (decreasing step)
    const DP_UP = new Array(N).fill(0);
    const DP_DOWN = new Array(N).fill(0);

    // Roots[i] stores the state of the PST after processing index i.
    // Roots_DOWN[i] summarizes DP_DOWN[j] for j <= i, indexed by nums[j].
    // Roots_UP[i] summarizes DP_UP[j] for j <= i, indexed by nums[j].
    const Roots_DOWN = new Array(N).fill(null);
    const Roots_UP = new Array(N).fill(null);

    // Initialize root for index -1 (empty tree)
    let lastRootDown = null;
    let lastRootUp = null;

    let maxScore = 0;

    for (let i = 0; i < N; i++) {
        const val = nums[i];

        // 1. Determine the previous eligible state (i - k)
        // We need information from indices j <= i - k.
        let eligibleRootDown = null;
        let eligibleRootUp = null;

        if (i >= k) {
            const prevIdx = i - k;
            eligibleRootDown = Roots_DOWN[prevIdx];
            eligibleRootUp = Roots_UP[prevIdx];
        }

        // 2. Query for M_DOWN and M_UP using eligible roots

        // M_DOWN: Max DP_DOWN[j] where nums[j] < val. Query range [1, val - 1]
        let M_DOWN = 0;
        if (eligibleRootDown) {
            M_DOWN = queryPST(eligibleRootDown, 1, V_MAX, 1, val - 1);
        }

        // M_UP: Max DP_UP[j] where nums[j] > val. Query range [val + 1, V_MAX]
        let M_UP = 0;
        if (eligibleRootUp) {
            M_UP = queryPST(eligibleRootUp, 1, V_MAX, val + 1, V_MAX);
        }

        // 3. Calculate DP[i]

        // Length 1 sequence always starts here: score is val.
        // If we extend, score is val + M.
        DP_UP[i] = val + Math.max(M_DOWN, 0);
        DP_DOWN[i] = val + Math.max(M_UP, 0);

        maxScore = Math.max(maxScore, DP_UP[i], DP_DOWN[i]);

        // 4. Update PSTs for index i

        // Update Roots_DOWN[i] using DP_DOWN[i] at value val, based on previous state Roots_DOWN[i-1]
        let prevRootDown = (i > 0) ? Roots_DOWN[i-1] : null;
        Roots_DOWN[i] = updatePST(prevRootDown, 1, V_MAX, val, DP_DOWN[i]);

        // Update Roots_UP[i] using DP_UP[i] at value val, based on previous state Roots_UP[i-1]
        let prevRootUp = (i > 0) ? Roots_UP[i-1] : null;
        Roots_UP[i] = updatePST(prevRootUp, 1, V_MAX, val, DP_UP[i]);
    }

    return maxScore;
}

