        DP_UP[i] = val_i + maxOf(M_DOWN, 0L)

        // DP_DOWN[i] = nums[i] + max(0, M_UP)
        DP_DOWN[i] = val_i + maxOf(M_UP, 0L)

        maxScore = maxOf(maxScore, DP_UP[i], DP_DOWN[i])

        // 4. Update PSTs for index i

        // Update Roots_DOWN[i] based on Roots_DOWN[i-1]
        val prevRootDown = if (i > 0) Roots_DOWN[i - 1] else null
        Roots_DOWN[i] = updatePST(prevRootDown, 1, V_MAX, val_i.toInt(), DP_DOWN[i])

        // Update Roots_UP[i] based on Roots_UP[i-1]
